export interface SettlementServiceImplementation<CallContextExt = {}> {
  /** List available funding instruments for the user. */
  listFundingInstruments(
    request: ListFundingInstrumentsRequest,
    context: CallContext & CallContextExt,
  ): Promise<DeepPartial<ListFundingInstrumentsResponse>>;
  /** List settlement handlers supported by a provider. */
  listSettlementHandlers(
    request: ListSettlementHandlersRequest,
    context: CallContext & CallContextExt,
  ): Promise<DeepPartial<ListSettlementHandlersResponse>>;
  /** Initiate a deposit. */
  deposit(request: DepositRequest, context: CallContext & CallContextExt): Promise<DeepPartial<SettlementTransaction>>;
  /** Initiate a withdrawal. */
  withdraw(
    request: WithdrawRequest,
    context: CallContext & CallContextExt,
  ): Promise<DeepPartial<SettlementTransaction>>;
  /** Get transaction status. */
  getTransaction(
    request: GetTransactionRequest,
    context: CallContext & CallContextExt,
  ): Promise<DeepPartial<SettlementTransaction>>;
  /** List transaction history. */
  listTransactions(
    request: ListTransactionsRequest,
    context: CallContext & CallContextExt,
  ): Promise<DeepPartial<ListTransactionsResponse>>;
}

